import { h, Signal } from '@tu-lang/runtime'

export const frontmatter = new Signal.State({})
export const Page = () => h("div", {}, [h("$static", {}, [], "<article class=\"tu-markdown\"><h1>Tu — Agent Skill</h1>\n<blockquote>\n<p><strong>Audience</strong>: LLM agents (Claude, GPT, etc.) that need to write or reason about Tu source code. This page is written for ingestion by automated tools — copy-paste it into a system prompt, save it as <code>.claude/skills/tu/SKILL.md</code>, or <code>fetch</code> it programmatically. A plain-text version is mirrored at <a href=\"./llms.txt\"><code>/llms.txt</code></a>.</p>\n</blockquote>\n<h2>Identity (the one-liner you need to keep in mind)</h2>\n<p>Tu is a <strong>reactive UI language</strong> that compiles to JS/TS. It is <strong>JS-superset-with-types-via-TS</strong> in spirit — most JS expression-level constructs work, types come from TypeScript (Volar pattern), reactivity comes from TC39 Signals. The grammar <strong>converges JS, never collides with active TC39 proposals</strong>.</p>\n<p>The compiler maps Tu source to TS shadow files; tsserver does the type checking. The runtime is a tiny Signal + DOM glue layer. There is no virtual machine and no custom runtime — it’s vanilla JS at runtime, with <code>Signal.State</code> / <code>Signal.Computed</code> cells as the only library-level primitive.</p>\n<p>Mental model order when reading Tu:</p>\n<ol>\n<li><strong>Top-level <code>let</code></strong> — module-private binding. Auto-binds to a <code>Signal.State</code> cell unless the value is a <code>() =&gt; …</code> lambda (then it’s a plain const) or <code>computed(...)</code> (then <code>Signal.Computed</code>).</li>\n<li><strong>Lambdas are components</strong> — capitalized lambda → component callable as <code>Foo()</code> or <code>Foo() { children }</code>. Lowercase → HTML tag-call (in markup position) or plain function (in expression position).</li>\n<li><strong><code>{ … }</code> after a callee = children block</strong> — the trailing-closure DSL. Each child is whitespace-separated; no <code>;</code> or <code>,</code> between children.</li>\n<li><strong>Markup, props, and style live in one syntax</strong>, top-to-bottom.</li>\n</ol>\n<h2>File anatomy</h2>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#6A737D\">// 1. Imports. Sources end in .tu (cross-Tu) or are bare (npm packages).</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Fragment</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"@tu-lang/runtime\"</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Card</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"./Card.tu\"</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 2. Type aliases (TS-style; raw RHS preserved to TS shadow).</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">type </span><span style=\"color:#B392F0\">Point</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\">; </span><span style=\"color:#B392F0\">y</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 3. Module-private cell (top-level `let` → Signal.State&#x3C;number>).</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 4. Public cell (export → consumers can import the cell).</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#F97583\"> let</span><span style=\"color:#B392F0\"> origin</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#B392F0\">Point</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">y</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 5. Computed cell (re-derives when its read-cells mutate).</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#F97583\"> let</span><span style=\"color:#E1E4E8\"> doubled </span><span style=\"color:#F97583\">=</span><span style=\"color:#F97583\"> computed</span><span style=\"color:#E1E4E8\">(count </span><span style=\"color:#F97583\">*</span><span style=\"color:#79B8FF\"> 2</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 6. Component (capitalized lambda; not wrapped in a Signal cell).</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#F97583\"> let</span><span style=\"color:#B392F0\"> App</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#B392F0\">children</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#B392F0\">Child</span><span style=\"color:#E1E4E8\">[]) </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> .</span><span style=\"color:#85E89D\">panel</span><span style=\"color:#E1E4E8\">() {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  h1</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"count = \"</span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#9ECBFF\">\" (doubled = \"</span><span style=\"color:#E1E4E8\"> doubled </span><span style=\"color:#9ECBFF\">\")\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  button</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">onClick</span><span style=\"color:#E1E4E8\">: () </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">+</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#9ECBFF\">\"+1\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  children</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">  style</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    .panel</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#79B8FF\">font-family</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">system-ui</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#79B8FF\">sans-serif</span><span style=\"color:#E1E4E8\">; </span><span style=\"color:#79B8FF\">padding</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">1</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">; }</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    .panel</span><span style=\"color:#F97583\"> ></span><span style=\"color:#85E89D\"> h1</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#79B8FF\">color</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">#312e81</span><span style=\"color:#E1E4E8\">; }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h2>Bindings</h2>\n<h3><code>let X = value</code></h3>\n<p>Module-private.</p>\n<ul>\n<li><strong>Value is a primitive / object literal / array literal / <code>[…]</code> / call result</strong> → <code>let X = …</code> compiles to <code>const X = new Signal.State(…)</code>.</li>\n<li><strong>Value is <code>(args) =&gt; body</code></strong> → plain <code>const X = (args) =&gt; body</code>. Not wrapped.</li>\n<li><strong>Value is <code>computed(expr)</code></strong> → <code>const X = new Signal.Computed(() =&gt; expr)</code>.</li>\n</ul>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#6A737D\">                       // Signal.State&#x3C;number></span></span>\n<span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#E1E4E8\"> make </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> (n) </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> n </span><span style=\"color:#F97583\">*</span><span style=\"color:#79B8FF\"> 2</span><span style=\"color:#6A737D\">              // plain function, no cell</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#E1E4E8\"> doubled </span><span style=\"color:#F97583\">=</span><span style=\"color:#F97583\"> computed</span><span style=\"color:#E1E4E8\">(count </span><span style=\"color:#F97583\">*</span><span style=\"color:#79B8FF\"> 2</span><span style=\"color:#E1E4E8\">)    </span><span style=\"color:#6A737D\">// Signal.Computed&#x3C;number></span></span>\n<span class=\"line\"></span></code></pre>\n<h3><code>export let X = value</code></h3>\n<p>Public — appears in the module’s named exports. Same wrapping rules as bare <code>let</code>.</p>\n<h3>Annotated bindings</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#B392F0\"> count</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#F97583\"> =</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#6A737D\">                // Signal.State&#x3C;number></span></span>\n<span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#B392F0\"> names</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">string</span><span style=\"color:#E1E4E8\">[] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> []             </span><span style=\"color:#6A737D\">// Signal.State&#x3C;string[]></span></span>\n<span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#B392F0\"> snap</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#B392F0\">Point</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">y</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\"> }     </span><span style=\"color:#6A737D\">// Signal.State&#x3C;Point></span></span>\n<span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#B392F0\"> cell</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#B392F0\">Signal</span><span style=\"color:#E1E4E8\">.</span><span style=\"color:#B392F0\">State</span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#B392F0\">MyT</span><span style=\"color:#F97583\">></span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> …      </span><span style=\"color:#6A737D\">// user opts out of double-wrap; the</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">                                     // compiler honors a pre-wrapped Signal.* type</span></span>\n<span class=\"line\"></span></code></pre>\n<p>The annotation is a raw source slice (depth-tracked across <code>()</code>, <code>{}</code>, <code>[]</code>, <code>&lt;…&gt;</code>). The TS-mode emit threads it through verbatim; JS-mode strips it.</p>\n<h3>Local <code>let</code> (inside a block)</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#B392F0\"> App</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> () </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">  let</span><span style=\"color:#E1E4E8\"> greeting </span><span style=\"color:#F97583\">=</span><span style=\"color:#9ECBFF\"> \"Hello, \"</span><span style=\"color:#F97583\"> +</span><span style=\"color:#E1E4E8\"> name </span><span style=\"color:#F97583\">+</span><span style=\"color:#9ECBFF\"> \"!\"</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  p</span><span style=\"color:#E1E4E8\"> { greeting }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<p>A local <code>let</code> is a <strong>plain const</strong>, not a Signal cell. It exists for closures, derived values, and small locals. Block bodies with one or more <code>let</code>s compile to an IIFE.</p>\n<h2>Type aliases</h2>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">type </span><span style=\"color:#B392F0\">Point</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\">; </span><span style=\"color:#B392F0\">y</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">type </span><span style=\"color:#B392F0\">RGB</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> readonly [number, number, number]</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#E1E4E8\"> type </span><span style=\"color:#B392F0\">AppProps</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">children</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#B392F0\">Child</span><span style=\"color:#E1E4E8\">[] }</span></span>\n<span class=\"line\"></span></code></pre>\n<p><code>type</code> is a contextual keyword (only triggers when followed by <code>Ident =</code> at statement boundary). The RHS is captured verbatim and emitted into the TS shadow. JS mode erases the entire alias.</p>\n<h2>Values</h2>\n<h3>Literals</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#9ECBFF\">\"a string\"</span><span style=\"color:#6A737D\">                  // StringLit (escapes: \\n \\t \\r \\\" \\\\)</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">42</span><span style=\"color:#6A737D\">                          // NumberLit (integers only at lexer level; decimals work via JS)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">[</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#79B8FF\">2</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#79B8FF\">3</span><span style=\"color:#E1E4E8\">]                   </span><span style=\"color:#6A737D\">// ArrayLit</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">[]                          </span><span style=\"color:#6A737D\">// empty ArrayLit (Signal.State&#x3C;any[]> auto-widened)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">{ </span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">y</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">2</span><span style=\"color:#E1E4E8\"> }              </span><span style=\"color:#6A737D\">// ObjectLit</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">{ </span><span style=\"color:#9ECBFF\">\"data-id\"</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">7</span><span style=\"color:#E1E4E8\"> }            </span><span style=\"color:#6A737D\">// ObjectLit with string key</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">{}                          </span><span style=\"color:#6A737D\">// EMPTY OBJECT — not an empty block</span></span>\n<span class=\"line\"></span></code></pre>\n<p><code>{</code> is disambiguated against the block form by lookahead: <code>{ }</code>, <code>{ Ident :</code>, or <code>{ String :</code> triggers an ObjectLit. Anything else (<code>{ x }</code>, <code>{ let y = 1; y }</code>, <code>{ tag(...) }</code>) stays a Block.</p>\n<p><strong>Not yet supported</strong> (don’t emit these — see the <a href=\"./DEFERRED\">Deferred backlog</a>):</p>\n<ul>\n<li>Object shorthand: <code>{ x }</code> — write <code>{ x: x }</code></li>\n<li>Computed keys: <code>{ [k]: v }</code></li>\n<li>Spread: <code>{ ...rest }</code>, <code>[...arr]</code></li>\n</ul>\n<h3>Identifiers + member access</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">count                       </span><span style=\"color:#6A737D\">// bare ident — reads the binding</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">origin.x                    </span><span style=\"color:#6A737D\">// member access (postfix)</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">make</span><span style=\"color:#E1E4E8\">(n).field               </span><span style=\"color:#6A737D\">// member access on a call result</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">nested.outer.inner          </span><span style=\"color:#6A737D\">// chained</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Member access <strong>only</strong> works on value-yielding expressions — <code>Ident</code>, plain <code>CallExpr</code> (no children block), existing <code>MemberExpr</code>, <code>ObjectLit</code>, <code>ArrayLit</code>. It does <strong>not</strong> work after a <code>TagCall</code> / <code>IfExpr</code> / <code>Block</code> / lambda body. This rule prevents <code>div { x }\\n.body() { y }</code> from re-parsing as <code>(div{x}).body(){y}</code>.</p>\n<h3>Lambdas</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">(x) </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> x </span><span style=\"color:#F97583\">+</span><span style=\"color:#79B8FF\"> 1</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\">) </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> x </span><span style=\"color:#F97583\">+</span><span style=\"color:#79B8FF\"> 1</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">name</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">string</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">age</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\">) </span><span style=\"color:#F97583\">=></span><span style=\"color:#85E89D\"> p</span><span style=\"color:#E1E4E8\"> { name }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">() </span><span style=\"color:#F97583\">=></span><span style=\"color:#85E89D\"> p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"hi\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\">): </span><span style=\"color:#79B8FF\">string</span><span style=\"color:#F97583\"> =></span><span style=\"color:#9ECBFF\"> \"ok\"</span><span style=\"color:#6A737D\">               // return-type annotation</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">(): </span><span style=\"color:#B392F0\">Map</span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\">string, { </span><span style=\"color:#B392F0\">v</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">number</span><span style=\"color:#E1E4E8\"> }</span><span style=\"color:#F97583\">></span><span style=\"color:#F97583\"> =></span><span style=\"color:#E1E4E8\"> empty   </span><span style=\"color:#6A737D\">// generics + nested types OK</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Param types and return types are raw slices — preserved in TS mode, erased in JS mode. The body is any expression (including a Block, IfExpr, ForExpr, TagCall, ObjectLit, …).</p>\n<h3>Calls</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#85E89D\">foo</span><span style=\"color:#E1E4E8\">(arg, another)           </span><span style=\"color:#6A737D\">// CallExpr — positional args</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">make</span><span style=\"color:#E1E4E8\">({ </span><span style=\"color:#B392F0\">x</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\"> })              </span><span style=\"color:#6A737D\">// arg can be any expression</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Identifiers followed by <code>(</code> and positional args (no <code>Ident:</code> immediately inside) parse as call expressions. The result is whatever the function returns.</p>\n<h3>Blocks</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">{</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  someStmt</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  anotherStmt</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  finalExpr      </span><span style=\"color:#6A737D\">// value of the block</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Each item is parsed as an expression (or a <code>LocalLet</code>). The last non-LocalLet expression is the block’s value. Multi-statement blocks compile to an IIFE; single-statement blocks compile to <code>(stmt)</code>. <strong>Note: <code>{}</code> is an empty object literal, not an empty block</strong> — write <code>{ undefined }</code> if you want a block that evaluates to <code>undefined</code>.</p>\n<h2>Markup (tag-calls)</h2>\n<p>Trailing-closure DSL. <strong>Capitalization is the discriminator</strong> (mirrors React/JSX):</p>\n<ul>\n<li><strong>Lowercase identifier</strong> → <code>h(&quot;tag&quot;, props, children)</code> — an HTML element.</li>\n<li><strong>Uppercase identifier</strong> → <code>Callee(args, [children])</code> — a real component function call.</li>\n</ul>\n<h3>Bare tag with children</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#85E89D\">div</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"Hello\"</span><span style=\"color:#E1E4E8\"> }                   → </span><span style=\"color:#85E89D\">h</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"div\"</span><span style=\"color:#E1E4E8\">, {}, [</span><span style=\"color:#9ECBFF\">\"Hello\"</span><span style=\"color:#E1E4E8\">])</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">h1</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"title\"</span><span style=\"color:#85E89D\"> p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"body\"</span><span style=\"color:#E1E4E8\"> } }       → </span><span style=\"color:#85E89D\">h</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"h1\"</span><span style=\"color:#E1E4E8\">, {}, [</span><span style=\"color:#9ECBFF\">\"title\"</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#85E89D\">h</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"p\"</span><span style=\"color:#E1E4E8\">, {}, [</span><span style=\"color:#9ECBFF\">\"body\"</span><span style=\"color:#E1E4E8\">])])</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Children are <strong>whitespace-separated</strong>, NOT comma-separated. Newlines / spaces between them are insignificant.</p>\n<h3>Tag with named props</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#85E89D\">div</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"card\"</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">id</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"main\"</span><span style=\"color:#E1E4E8\">) { … }</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">button</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">onClick</span><span style=\"color:#E1E4E8\">: () </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">+</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#9ECBFF\">\"+1\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">input</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">type</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"text\"</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">value</span><span style=\"color:#E1E4E8\">: name)</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Props are <code>name: value</code> pairs separated by <code>,</code>. Values can be any expression — strings, idents (cell reads inject <code>.get()</code>), lambdas, ObjectLits, ClassRefs, etc.</p>\n<h3>Component invocation</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#79B8FF\">Card</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"title\"</span><span style=\"color:#E1E4E8\">)                     → </span><span style=\"color:#79B8FF\">Card</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"title\"</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">Card</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"title\"</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#85E89D\">p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"body\"</span><span style=\"color:#E1E4E8\"> } }    → </span><span style=\"color:#79B8FF\">Card</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"title\"</span><span style=\"color:#E1E4E8\">, [</span><span style=\"color:#85E89D\">h</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"p\"</span><span style=\"color:#E1E4E8\">, {}, [</span><span style=\"color:#9ECBFF\">\"body\"</span><span style=\"color:#E1E4E8\">])])</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">Card</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#85E89D\">p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"no args, just kids\"</span><span style=\"color:#E1E4E8\"> } }  → </span><span style=\"color:#79B8FF\">Card</span><span style=\"color:#E1E4E8\">([</span><span style=\"color:#85E89D\">h</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">\"p\"</span><span style=\"color:#E1E4E8\">, {}, [</span><span style=\"color:#9ECBFF\">\"no args, just kids\"</span><span style=\"color:#E1E4E8\">])])</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Components are real functions. tsserver sees them as such — hover, goto-definition, and rename all work cross-<code>.tu</code>. The trailing children block becomes the <strong>last positional argument</strong>, conventionally typed as <code>(children: Child[])</code>.</p>\n<h3>Fragment (multi-root return)</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Fragment</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"@tu-lang/runtime\"</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#B392F0\"> App</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> () </span><span style=\"color:#F97583\">=></span><span style=\"color:#79B8FF\"> Fragment</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  header</span><span style=\"color:#E1E4E8\"> { … }</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  main</span><span style=\"color:#E1E4E8\"> { … }</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  footer</span><span style=\"color:#E1E4E8\"> { … }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<p><code>Fragment</code> is a built-in helper that takes the children array and returns it as-is, letting a component return multiple sibling vnodes without an enclosing wrapper.</p>\n<h3>Pug-style class shorthand</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">.card                             </span><span style=\"color:#6A737D\">// ClassRef (used as a value, e.g. class: .card)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">.card.elevated                    </span><span style=\"color:#6A737D\">// multi-class binding</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">.</span><span style=\"color:#85E89D\">card</span><span style=\"color:#E1E4E8\">() { </span><span style=\"color:#9ECBFF\">\"x\"</span><span style=\"color:#E1E4E8\"> }                   → </span><span style=\"color:#85E89D\">div</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"card …\"</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#9ECBFF\">\"x\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">.card.</span><span style=\"color:#85E89D\">elevated</span><span style=\"color:#E1E4E8\">() { </span><span style=\"color:#9ECBFF\">\"x\"</span><span style=\"color:#E1E4E8\"> }          → </span><span style=\"color:#85E89D\">div</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"card elevated …\"</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#9ECBFF\">\"x\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">.</span><span style=\"color:#85E89D\">card</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">tag</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"section\"</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#9ECBFF\">\"x\"</span><span style=\"color:#E1E4E8\"> }     </span><span style=\"color:#6A737D\">// override default tag with a string literal</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Pug-shorthand desugars to a <code>div</code> (or the <code>tag:</code> override) with the listed classes injected. An explicit <code>class:</code> prop in shorthand-position is a parse error — the shorthand already binds class.</p>\n<h3>Children types</h3>\n<p>A child can be: TagCall, CallExpr, BinaryExpr, StringLit, NumberLit, Ident, IfExpr, ForExpr, StyleBlock, ClassRef, ArrayLit, ObjectLit, MemberExpr.</p>\n<p>A child <strong>cannot</strong> be: Lambda, Block, AssignExpr (these throw at parse time).</p>\n<h2>Control flow</h2>\n<h3><code>if</code> / <code>else</code></h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">if</span><span style=\"color:#E1E4E8\"> (count </span><span style=\"color:#F97583\">></span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#85E89D\">p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"positive: \"</span><span style=\"color:#E1E4E8\"> count } }</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">else</span><span style=\"color:#F97583\"> if</span><span style=\"color:#E1E4E8\"> (count </span><span style=\"color:#F97583\">==</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#85E89D\">p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"zero\"</span><span style=\"color:#E1E4E8\"> } }</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">else</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#85E89D\">p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"negative\"</span><span style=\"color:#E1E4E8\"> } }</span></span>\n<span class=\"line\"></span></code></pre>\n<p>The condition is parenthesized; both branches are blocks. Else-if chains are supported as nested IfExpr. <code>if</code> is an expression — its value is the chosen branch’s block-value.</p>\n<h3><code>for</code></h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">for</span><span style=\"color:#E1E4E8\"> item </span><span style=\"color:#F97583\">in</span><span style=\"color:#85E89D\"> items</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  li</span><span style=\"color:#E1E4E8\"> { item }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Compiles roughly to <code>Array.from(items, (item) =&gt; …)</code>. The iterable’s tail <code>{ … }</code> is the loop body, <strong>not</strong> a tag-call on the iterable (the parser suppresses brace-block parsing inside the iter expression for exactly this reason).</p>\n<h2>Reactivity</h2>\n<ul>\n<li>Top-level <code>let X = …</code> (non-lambda, non-<code>computed(…)</code>) → <code>Signal.State&lt;T&gt;</code>. Reads of <code>X</code> inside any expression context emit as <code>X.get()</code>. Assignments <code>X = expr</code> desugar to <code>X.set(expr)</code>.</li>\n<li><code>let X = computed(expr)</code> → <code>Signal.Computed&lt;T&gt;</code> whose body re-runs whenever any cell read inside <code>expr</code> mutates.</li>\n<li><strong>Local <code>let</code></strong> (inside a block) is a plain const; reads/writes pass through unchanged.</li>\n<li><strong>Lambda params</strong> are plain idents (no <code>.get()</code> injection).</li>\n<li><code>mount(thunk, container)</code> re-runs <code>thunk</code> whenever any cell it reads mutates.</li>\n<li><code>computed(...)</code> cells lazily re-evaluate on read after invalidation.</li>\n</ul>\n<p>The <code>.get()</code> injection rule: a bare ident emits as <code>name.get()</code> if and only if <code>name</code> resolves to a top-level state or computed cell <strong>and</strong> is not shadowed by a local <code>let</code>, lambda param, or <code>for</code> binder.</p>\n<h2>Style block</h2>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">let</span><span style=\"color:#B392F0\"> Card</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#B392F0\">title</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">string</span><span style=\"color:#E1E4E8\">) </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> .</span><span style=\"color:#85E89D\">card</span><span style=\"color:#E1E4E8\">() {</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  h1</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: .card__title) { title }</span></span>\n<span class=\"line\"><span style=\"color:#85E89D\">  p</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#9ECBFF\">\"body\"</span><span style=\"color:#E1E4E8\"> }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">  style</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    .card</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#79B8FF\">padding</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">1</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">; </span><span style=\"color:#79B8FF\">border-radius</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">8</span><span style=\"color:#F97583\">px</span><span style=\"color:#E1E4E8\">; }</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    .card__title</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#79B8FF\">font-size</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">1.25</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">; }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    :global(</span><span style=\"color:#B392F0\">.legacy</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#79B8FF\">color</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">gray</span><span style=\"color:#E1E4E8\">; }   // unscoped escape </span><span style=\"color:#85E89D\">hatch</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<ul>\n<li><code>style { … }</code> is a special form (no parens). The body is raw CSS, preserved verbatim in the StyleBlock AST and emitted as a <code>&lt;style&gt;</code> sibling vnode.</li>\n<li><strong>Top-level CSS rules must be class-rooted</strong> (M5/D). <code>body { … }</code> or <code>* { … }</code> at the top level is a compile error. Nested rules (<code>.card &gt; h1 { … }</code>) are fine.</li>\n<li><strong>Scoped classes</strong> (M5/F dual-class injection): every <code>ClassRef</code> in the markup gets BOTH the original name AND a per-component hashed name (<code>&lt;div class=&quot;card card-tu-XXX&quot;&gt;</code>). The CSS rewriter rewrites the selector to the hashed form (<code>.card-tu-XXX { … }</code>). Global selectors / dev-tools targeting <code>.card</code> still work, but <code>.card</code>’s rules don’t bleed across components.</li>\n<li><strong><code>:global(.foo)</code></strong>: escape hatch — selectors inside this wrapper stay unhashed.</li>\n</ul>\n<h3>ClassRef syntax</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">.card                             </span><span style=\"color:#6A737D\">// bare ClassRef — used as a value</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: .card                      </span><span style=\"color:#6A737D\">// assigned to the class prop</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">class</span><span style=\"color:#E1E4E8\">: .card.elevated             </span><span style=\"color:#6A737D\">// multi-class space-joined</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">.</span><span style=\"color:#85E89D\">card</span><span style=\"color:#E1E4E8\">() { … }                     </span><span style=\"color:#6A737D\">// pug-shorthand (see above)</span></span>\n<span class=\"line\"></span></code></pre>\n<p>A <code>ClassRef</code> to an <strong>undeclared</strong> class (one not declared in the enclosing component’s <code>style { … }</code> block) is a compile error.</p>\n<h2>Imports / exports</h2>\n<h3>Named import</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Card</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"./Card.tu\"</span><span style=\"color:#6A737D\">        // cross-.tu (sibling)</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Fragment</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"@tu-lang/runtime\"</span><span style=\"color:#6A737D\">  // npm package</span></span>\n<span class=\"line\"></span></code></pre>\n<p>V1 supports named imports only. No default imports, no namespace imports.</p>\n<h3>Re-export</h3>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">export</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#B392F0\">Card</span><span style=\"color:#E1E4E8\"> } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> \"./Card.tu\"</span></span>\n<span class=\"line\"></span></code></pre>\n<h3>Cross-<code>.tu</code> reactivity</h3>\n<p>When you import a state/computed cell from another <code>.tu</code>, the importer’s codegen knows to inject <code>.get()</code> on reads. The compiler analyzes the imported module’s AST to classify each export’s CellKind.</p>\n<h2>Common gotchas (study these — they prevent bugs)</h2>\n<ol>\n<li><strong><code>{}</code> is an empty OBJECT, not an empty block.</strong> Write <code>{ undefined }</code> for an empty block.</li>\n<li><strong>Children are whitespace-separated.</strong> Don’t write <code>,</code> between them: <code>div { x, y }</code> parses as <code>div { (x, y) }</code> which is not what you want.</li>\n<li><strong>No shorthand object props yet.</strong> <code>{ x }</code> is a Block, not <code>{ x: x }</code>. Write the key explicitly.</li>\n<li><strong>No spread / computed keys / member access via <code>[]</code>.</strong> Use object literal + member access via <code>.</code> only.</li>\n<li><strong><code>.foo()</code> after a sibling expression is NOT a method call.</strong> It’s pug-shorthand for the next element. <code>tag1 { x }\\n.foo() { y }</code> parses as two siblings, not one chained call. (Member access <code>obj.foo</code> only applies to value-yielding exprs.)</li>\n<li><strong>Capitalized names are components, lowercase are HTML tags.</strong> <code>Card { … }</code> and <code>card { … }</code> parse to entirely different things.</li>\n<li><strong>Style block top-level rules must be class-rooted.</strong> No <code>body</code>, <code>*</code>, <code>:root</code> at the top level (use <code>:global(...)</code> if you really need them).</li>\n<li><strong>An explicit <code>class:</code> prop inside a pug-shorthand is an error.</strong> The shorthand already binds class.</li>\n<li><strong>No <code>match</code> / pattern matching.</strong> Removed in M1.11 due to TC39 Pattern Matching collision. Use chained <code>if / else if / else</code>.</li>\n<li><strong>No <code>function</code> keyword anywhere.</strong> All functions are arrow-style <code>(args) =&gt; body</code>.</li>\n<li><strong>No <code>class</code> keyword for OOP.</strong> Tu is immutable-by-default; user-defined types are functions, not classes.</li>\n<li><strong>No member access through <code>()</code> chained results.</strong> <code>make(n).x</code> works; <code>Card(&quot;hi&quot;) { … }.x</code> does not (the second is a vnode, not a value).</li>\n</ol>\n<h2>Compilation model (high-level)</h2>\n<p>Each <code>.tu</code> file compiles to a single <code>.js</code> (or <code>.ts</code> shadow) module. The compiler:</p>\n<ol>\n<li><strong>Tokenizes</strong> the source (lexer in <code>packages/compiler/src/lexer.ts</code>).</li>\n<li><strong>Parses</strong> to AST (<code>parser.ts</code>). All AST nodes carry <code>start</code> / <code>end</code> byte offsets for source maps + LSP.</li>\n<li><strong>Analyzes</strong> scoped components: every <code>let X = (...) =&gt; …</code> whose body uses <code>ClassRef</code>s gets a per-component hash (FNV-1a over name + style-body). Declared classes are extracted from the style block’s CSS via a regex scanner.</li>\n<li><strong>Generates</strong> JS/TS via a streaming buffer that records <code>TokenMapping</code>s as it emits. Top-level lets become <code>const X = new Signal.State(…)</code> / <code>Signal.Computed(…)</code> / plain const based on classification. Tag-calls become <code>h(&quot;tag&quot;, props, children)</code>. Component calls stay as real function calls. Pug-shorthand desugars in the AST. ClassRefs emit hashed class strings. Style blocks emit as <code>&lt;style&gt;</code> vnode children with the CSS rewritten.</li>\n<li><strong>Source maps</strong> are V3, per-token + per-statement.</li>\n</ol>\n<p>The runtime is <code>@tu-lang/runtime</code> — <code>h(tag, props, children)</code>, <code>mount(thunk, container)</code>, <code>hydrate(thunk, container)</code>, <code>renderToString(node)</code>, <code>Fragment(children)</code>, <code>Signal.State</code>, <code>Signal.Computed</code>. Mount drives a keyed diff (LIS-based reorder, focus / scroll / <code>&lt;input&gt;</code> value preserved).</p>\n<h2>Testing pattern</h2>\n<p>Per-package tests live in <code>packages/&lt;name&gt;/tests/</code>. Compiler tests:</p>\n<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#6A737D\">// packages/compiler/tests/parser.test.ts</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { describe, expect, it } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> 'vitest'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { tokenize } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '../src/lexer.js'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { parse } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '../src/parser.js'</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">function</span><span style=\"color:#B392F0\"> ast</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#FFAB70\">src</span><span style=\"color:#F97583\">:</span><span style=\"color:#79B8FF\"> string</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#F97583\">return</span><span style=\"color:#B392F0\"> parse</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">tokenize</span><span style=\"color:#E1E4E8\">(src), src) }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#B392F0\">describe</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">'parser'</span><span style=\"color:#E1E4E8\">, () </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">  it</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">'parses an export let with object literal'</span><span style=\"color:#E1E4E8\">, () </span><span style=\"color:#F97583\">=></span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    const</span><span style=\"color:#79B8FF\"> tree</span><span style=\"color:#F97583\"> =</span><span style=\"color:#B392F0\"> ast</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">'export let p = { x: 1 }'</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    expect</span><span style=\"color:#E1E4E8\">(tree.body[</span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">]).</span><span style=\"color:#B392F0\">toMatchObject</span><span style=\"color:#E1E4E8\">({</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">      kind: </span><span style=\"color:#9ECBFF\">'LetDecl'</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">      exported: </span><span style=\"color:#79B8FF\">true</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">      name: </span><span style=\"color:#9ECBFF\">'p'</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">      value: { kind: </span><span style=\"color:#9ECBFF\">'ObjectLit'</span><span style=\"color:#E1E4E8\">, properties: [{ key: </span><span style=\"color:#9ECBFF\">'x'</span><span style=\"color:#E1E4E8\"> }] },</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    })</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">  })</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">})</span></span>\n<span class=\"line\"></span></code></pre>\n<p>Codegen tests assert on the emitted JS string. Integration tests (<code>tests/integration.test.ts</code>) compile a Tu source, write the result to a temp <code>.mjs</code>, dynamic-import it, and exercise the exported cells/components against <code>renderToString</code> / <code>mount</code>.</p>\n<h2>Deferred features (do NOT emit these)</h2>\n<p>See the full list at <a href=\"./DEFERRED\">DEFERRED.md</a>. Quick exclusions:</p>\n<ul>\n<li><code>match</code> / pattern matching — removed in M1.11.</li>\n<li>Object shorthand <code>{ x }</code> / spread <code>{ ...r }</code> / computed keys <code>{ [k]: v }</code>.</li>\n<li>Array spread <code>[...arr]</code>.</li>\n<li>Indexed access <code>obj[&quot;key&quot;]</code> or <code>arr[i]</code>.</li>\n<li>Method calls <code>obj.foo()</code> (works only when <code>foo</code> is a real function field; no protocol/method overloading).</li>\n<li>Default exports.</li>\n<li><code>async</code> / <code>await</code> syntax (no async story yet).</li>\n<li>Per-component HMR.</li>\n<li>Static-HTML subtree optimization (post-M5).</li>\n</ul>\n<p>When unsure: <strong>stick to the constructs documented above</strong>. The language deliberately surfaces a small, opinionated set; if a JS-side feature isn’t listed here, it probably isn’t in V1.</p>\n<h2>Quick reference: emit shapes</h2>\n<table>\n<thead>\n<tr>\n<th>Tu</th>\n<th>JS emit</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><code>let count = 0</code></td>\n<td><code>const count = new Signal.State(0)</code></td>\n</tr>\n<tr>\n<td><code>let App = () =&gt; …</code></td>\n<td><code>const App = () =&gt; …</code> (plain)</td>\n</tr>\n<tr>\n<td><code>let d = computed(c * 2)</code></td>\n<td><code>const d = new Signal.Computed(() =&gt; (c.get() * 2))</code></td>\n</tr>\n<tr>\n<td><code>count = count + 1</code></td>\n<td><code>count.set(count.get() + 1)</code></td>\n</tr>\n<tr>\n<td><code>div { x }</code></td>\n<td><code>h(&quot;div&quot;, {}, [x.get()])</code></td>\n</tr>\n<tr>\n<td><code>Card(&quot;hi&quot;) { p { y } }</code></td>\n<td><code>Card(&quot;hi&quot;, [h(&quot;p&quot;, {}, [y.get()])])</code></td>\n</tr>\n<tr>\n<td><code>.card() { x }</code></td>\n<td><code>h(&quot;div&quot;, { class: &quot;card card-tu-XXX&quot; }, [x.get()])</code></td>\n</tr>\n<tr>\n<td><code>{ x: 1, y: 2 }</code></td>\n<td><code>{ x: 1, y: 2 }</code></td>\n</tr>\n<tr>\n<td><code>obj.x</code> (cell)</td>\n<td><code>obj.get().x</code></td>\n</tr>\n<tr>\n<td><code>obj.x</code> (param/local)</td>\n<td><code>obj.x</code></td>\n</tr>\n<tr>\n<td><code>for x in xs { … }</code></td>\n<td><code>Array.from(xs.get(), (x) =&gt; …)</code></td>\n</tr>\n</tbody>\n</table>\n<h2>Related resources</h2>\n<ul>\n<li><a href=\"./LANGUAGE\">Language reference</a> — every Tu syntactic form with examples and emit shapes.</li>\n<li><a href=\"./DEFERRED\">Deferred backlog</a> — every “leave for later” decision, indexed by milestone.</li>\n<li><a href=\"https://github.com/mowtwo/tu\">GitHub repository</a> — source, examples, playground.</li>\n<li><a href=\"./llms.txt\">llms.txt</a> — plain-text mirror of this skill for direct fetch.</li>\n</ul>\n<hr>\n<p><em>Tu is pre-alpha (<code>0.1.0-alpha.6</code> on npm). This skill reflects the language as of 2026-05-01 (M6.2 + tu-xing + tu-shu shipped; obj.x member access and obj.method() method calls both supported). When in doubt, read <a href=\"./LANGUAGE\">LANGUAGE.md</a> for the canonical reference, and check the <a href=\"https://github.com/mowtwo/tu/commits/main\">git log</a> for the latest changes.</em></p>\n</article>")])
